export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:13。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲。不止一雙。從通道入口的方向傳過來，急促，沉重，塑膠隔離簾被扯開又彈回去的聲音。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪抬起頭。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個人。穿站務制服的。後面跟著一個穿深色制服的保全。他們繞過設備車，衝進通道，手電筒的光柱在牆上掃來掃去。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "請離開傷者！", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "把手舉起來！", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪跪在血裡。雙手壓著千田的肋下。圍巾已經濕透了。她的手、她的手腕、她的袖口——全是暗紅色的。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他們以為是我做的。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "不是我。有維修人員從側門跑了！", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音比自己想像的啞。喉嚨像被什麼堵住了。但她把每個字都推出來了。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站務員的手電筒照著她的臉。她瞇起眼睛。光太亮了。她看不清對方的表情，但她知道對方在看什麼——在看她的手。在看她手上的血。在看千田。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "先不要動。把手放在能看見的地方。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我在幫他止血。如果我鬆手他會——", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "救護已經叫了。妳先退後。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有退。她不能退。千田的呼吸很淺。圍巾上的血還在往外滲。她鬆手一秒，血就會從那個被壓住的位置湧出來。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後千田動了。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的嘴唇。很微弱的動作。像在含著一個說不出口的字。他的眼睛半開著，焦點不在任何人身上。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.ChidaKosuke, character: "千田浩介", dialogue: "⋯⋯不是⋯⋯維修⋯⋯", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.ChidaKosuke_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很碎。像氣音。但站務員聽見了。保全也聽見了。他們的手電筒同時照向千田的臉，又照回澪的臉。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他說「不是維修」。他在說那個人不只是維修人員。或者他在說那個人不是真的維修人員。但這句話——", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這句話不能單獨替我脫罪。他沒有說「不是她」。他說的是「不是維修」。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站務員蹲下來，看了千田一眼。又看了澪一眼。他的手電筒從她的臉移到她的手——壓在傷口上的手。圍巾。血。壓迫的姿勢。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "妳是怎麼進來的？", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "施工搬運通道。隔離簾旁邊的縫。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "妳認識這個人嗎？", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "不認識。我看到有人把他帶進來。穿維修服的。戴口罩和帽子。他從側門走了。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "保全已經往通道深處走了。他的手電筒照到側門——關著的。金屬門面。讀卡器上的綠光已經滅了，只剩下一個小小的紅色待機指示燈。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "側門關著的。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "剛才還開著。他刷卡出去的。讀卡器亮了綠光。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "保全伸手按了一下讀卡器。沒有反應。他又看了一眼門禁面板上的小螢幕——上面只有一串簡短的代碼，沒有姓名，沒有部門。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "施工通道二號門。讀卡紀錄只有代碼。要調取使用者資料需要更高權限。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拿起對講機。開始聯絡控制中心。聲音在通道裡回響，和通風設備的低頻嗡鳴混在一起。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "控制中心，這裡是灣岸站施工通道。二號門有異常門禁紀錄，疑似臨時維修權限。請先保留門禁紀錄，不要覆寫。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "對講機裡傳來回覆。斷斷續續的。澪聽不清全部，但她聽到了幾個字。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "收到。中央流那邊有畫面嗎？", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "停頓。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "中央流沒有清楚畫面。轉角那一段不在乘客區監控範圍。入口鏡頭有拍到——", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看了澪一眼。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "入口鏡頭拍到一名女性在傷者之後進入通道。時間21:04。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯入口鏡頭拍到我進來。在千田之後。這對我有利。如果我是攻擊者，我不會在傷者之後進入——我會在他之前。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我觸發了緊急通報。我沒有持有任何凶器。我的手在壓迫止血。側門有異常權限紀錄。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這些加起來。暫時。只是暫時。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站務員的對講機又響了。他聽了一會兒，轉頭看保全。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "控制中心說側門權限紀錄需要走維修管理系統調取，站務端看不到。先封鎖通道，等警方和鑑識到場。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "保全點頭。他從腰間拿出一卷黃色警戒帶，開始在通道入口拉起來。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯中央流。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯又是中央流。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯那個維修人員給千田看平板的時候，上面就有「中央流」。站務員現在聯絡控制中心，也在說「中央流沒有清楚畫面」。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他不是隨便在路上攔住千田的。他知道今晚中央流有什麼問題。他知道哪一段沒有清楚畫面。他知道側門可以用臨時維修權限。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在用今晚的系統漏洞。不是碰巧。是知道。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她想開口。她想說——讓我看保全影像。讓我看側門的門禁紀錄。讓我看入口鏡頭的時間軸。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "那個側門的門禁紀錄——能不能現在調出來？還有入口鏡頭——", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "小姐，妳先退後。救護快到了。等警方到場會有人跟妳問話。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我知道我看到的是什麼——", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "我知道。但這裡現在是管制區。請妳配合。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的語氣不凶。但很硬。像一扇關上的門。不是因為他不相信她。是因為流程不允許她在這裡。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我不是警察。我不是站務。我不是保全。我是一個非法進入限制區的人。我說的每一句話，都會先變成「目擊者陳述」，然後被放進某個資料夾裡。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她退後了一步。只一步。她的膝蓋離開了血灘的邊緣，但她的眼睛還在看千田。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田的呼吸還在。很淺。很淺。他的手從肋下滑開了，無力地垂在身側。站務員蹲下來接替她的位置，用急救箱裡的紗布壓上去。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我把他從第七車裡救出來了。但他在這裡。在通道裡。在血裡。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我改變了死亡的地點。還沒有改變死亡本身。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.AsakuraMio_Base },
];
